var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"여러분 미하~ 오늘 컨텐츠는 카운터즈 레거시에서 전해드립니다!","JPN":"皆さん、ミハ～今日のコンテンツはカウンターズ・レガシーからお届けします！","ENG":"Hi, everyone. It's me, Miya! I'm here today to introduce Counters Legacy!","TWN":"大家好～今天的內容是從制裁者的遺產那邊得到的消息！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"이 복장은 그러니까…… 가람 씨가 은근슬쩍 계약서에 넣어둔 조항 때문에…….","JPN":"この服は……えっと……ヒカリさんが契約書にこっそり盛り込んだ条項のせいで……","ENG":"So, this outfit is, um... a clause that Garam secretly included in the contract...","TWN":"這身服裝是因為……嘉蘭小姐偷偷加在契約書裡的條款……"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"그, 그게 아니라 오늘은 제가 메인이라 한번 힘써봤어요……!\xA0\xA0","JPN":"というのは違って……今日は私がメインだから奮発してみました……！\xA0\xA0","ENG":"A-actually, I just wanted to put on something nice since I'm the star of the show today...!\xA0\xA0","TWN":"不，不是的，因為今天我是主角，所以稍微打扮了一下……！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>■■■</color> 바니걸 차림으로? ㅋㅋㅋ\\n<color=#ffd34c>■■■</color> 복장 뭐임? 벌써부터 고여 버린 거야?","JPN":"<color=#ffd34c>■■■</color> バニーガールの格好で？　ｗｗｗ\\n<color=#ffd34c>■■■</color> 何だよあの服？　もうガチ勢になったのかよ。","ENG":"<color=#ffd34c>■■■</color> In a bunny girl costume? LOL\\n<color=#ffd34c>■■■</color> What's with the outfit? Are you already an expert in the game?","TWN":"<color=#ffd34c>■■■</color> 兔女郎？呵呵呵\\n<color=#ffd34c>■■■</color>那身衣服怎麼回事？這麼懂玩？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"오늘은 하트베리 콜라보를 기념해서, 제가 퀘스트를 기획해 봤거든요.","JPN":"今日はハートベリーコラボを記念して、私がクエストを企画してみました。","ENG":"To commemorate the HRT Berry collaboration, I've planned a quest.","TWN":"今天為了紀念與愛心莓果的聯動，我策劃了一個任務。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"바로~ 미야의 굿즈 수집 퀘스트! 정말 간단하죠?","JPN":"じゃじゃーん～ミヤのグッズコレクトクエスト！　簡単でしょう？","ENG":"It's called! Miya's Merchandise Collecting Quest! Isn't it simple?","TWN":"就是～米婭的周邊收集任務！很簡單吧？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L8_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"맵에 표시된 구역에서 미야의 브로마이드를 얻으면 클리어에요.","JPN":"マップに記されたエリアで、ミヤのブロマイドを手に入れたらクリアです。","ENG":"All you have to do is obtain Miya's poster from the area marked on the map.","TWN":"在地圖上標記的區域獲得米婭的海報即可通關。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>■■■</color> 미야의 브로마이드라고????\\n<color=#ffd34c>■■■</color> 대체 무슨 사진을 찍었는데여???","JPN":"<color=#ffd34c>■■■</color> ミヤのブロマイド？？？\\n<color=#ffd34c>■■■</color>どんな写真なんですか？？","ENG":"<color=#ffd34c>■■■</color> Miya's poster????\\n<color=#ffd34c>■■■</color> What kind of photo is it???","TWN":"<color=#ffd34c>■■■</color>米婭的海報？？？\\n<color=#ffd34c>■■■</color>是什麼照片？？？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"무, 무슨 사진이냐고요? 지금 제가 입고 있는…….","JPN":"ど、どんな写真……？　今私が着ている……","ENG":"W-what kind of photo? It's what I'm wearing right–","TWN":"什，什麼照片？就是我現在穿的這件……"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"자세한 건 저희 채널에서 확인해 주세요……!!!","JPN":"詳しい内容は私たちのチャンネルでチェックしてください……！！","ENG":"Check out our channel for more details...!!!","TWN":"詳細內容請在我們的頻道查看……！！！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"그럼 가볼까요……?","JPN":"では行きましょうか……？","ENG":"Then, shall we...?","TWN":"那麼開始吧……？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"나 참…… 그 땅꼬마 녀석, 설마 하트베리의 스폰 때문에 날 이용한 건 아니겠지?","JPN":"ったく……あのチビ、まさかハートベリーのスポンサー目当てで私を利用したわけじゃないわよね。","ENG":"Ugh... That little kid. She's not using me for that sponsorship with HRT Berry, is she?","TWN":"我說……那個矮冬瓜，不會是因為愛心莓果的贊助才利用我的吧？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"당신이 그…… 하트베리의 보미 맞지? 퀘스트는 여기서 받으면 돼?","JPN":"あんたがその……ハートベリーのボミだよね？　クエストはここで受注すればいいの？","ENG":"You're, uh... Bomi from HRT Berry, right? Is this where I get the quest?","TWN":"你是那個……愛心莓果的普美對吧？任務在這裡領取嗎？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"시시한 퀘스트나 줄 거면 사양할게. 가장 어려운 걸로 줘!","JPN":"つまんないクエストはお断りだから。一番難しいやつにして！","ENG":"If it's a fetch quest, then I'll decline. Give me the hardest one you've got!","TWN":"如果任務很無聊，我可不幹。我要最難的任務！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L19_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"아카데미 학생이냥? 의욕이 넘치는 건 좋은거당.","JPN":"アカデミーの生徒かにゃ？　やる気に満ちているのはいいことだにゃ。","ENG":"Are you a student of the Academy? It's great how energetic you are.","TWN":"是學院的學生嗎？真是充滿幹勁呢。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"하지만 너무 무리하다 깜빡 잠에 들지 않게 조심하라냥.","JPN":"でも無理しすぎてうっかり眠っちゃわないように気をつけるにゃ。","ENG":"But be careful not to fall asleep while pushing yourself.","TWN":"但是不要太勉強自己，不要一不小心就睡著囉喵。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"장소는 맵에 표기해 놨당. 한번 잘 찾아보라냥~","JPN":"場所はマップに印をつけておいたにゃ。頑張って探してみるにゃ～","ENG":"I marked the location on your map. Happy hunting!","TWN":"地點已經標在地圖上了。快去找找看吧～"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"미야의 브로마이드 찾기……? 이딴 게 퀘스트라고……?!","JPN":"ミヤのブロマイド探し……？　こんなのがクエストなの……！？","ENG":"\\"Find Miya's Poster\\"...? This is the quest...?!","TWN":"尋找米婭的海報……？這也算任務嗎……？！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이봐, 지금 장난치는 거야? 좋은 말 할 때 어서 다른 걸로 내놔!","JPN":"ちょっと、ふざけてるの？　早く他のクエストをよこしなさい！","ENG":"Hey, are you kidding me right now? Take this back and give me something harder!","TWN":"喂，你現在是在開玩笑嗎？趁我還想好好說話的時候，趕緊換個別的出來！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"이 퀘스트를 얕보면 곤란하당. 벌써부터 경쟁자가 어마어마 하다냥.","JPN":"このクエストを甘く見ちゃ困るにゃ。すでにライバルたちがうじゃうじゃいるにゃ。","ENG":"You shouldn't underestimate this quest. The competition is already fierce.","TWN":"不要小看這個任務。現在已經有很多競爭者了喵。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"방금은 어떤 <color=#ffd34c>총잡이 소녀</color>도 있었는데, 부하들을 잔뜩 모은 것 같았당.","JPN":"さっきは<color=#ffd34c>ガンマン少女</color>もいたけど、部下をたくさんひき連れてきたみたいだったにゃ。","ENG":"I met a <color=#ffd34c>gunslinger girl</color> right before you, and she had a ton of underlings with her.","TWN":"剛才有個<color=#ffd34c>槍手少女</color>，好像召集了一大堆手下呢喵。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"분명 무시무시한 상대가 될거당.","JPN":"きっと恐ろしい相手になるにゃ。","ENG":"I'm sure she'll be a formidable opponent.","TWN":"肯定會成為一個可怕的對手。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥! 피 튀기는 전장은 이 몸에겐 익숙해서 말이야.","JPN":"ふん！　血まみれの戦場なんて、この私には慣れっこよ。","ENG":"Hmph! I'm already used to a bloody battlefield.","TWN":"哼！血腥的戰場對我來說已經習以為常了。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"하, 학생이라고 하지 않았냥……?","JPN":"せ、生徒じゃなかったにゃ……？","ENG":"D-didn't you say you were a student...?","TWN":"我記得你就是個學生吧喵……？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"후후, 부하들을 잔뜩 모아왔다고? 이 몸에게 숫자는 의미 없는데 말이야…….","JPN":"ふふ、部下をたくさん連れてきた？　私に数なんか意味ないのにね……","ENG":"*Scoff* A ton of underlings? Numbers mean nothing to me...","TWN":"呵呵，帶了這麼多手下過來嗎？對我來說，數量沒有任何意義……"},"stage":{"bg":"LEGACY_GROUND","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"근데…… 니들은 왜 따라온 거야?","JPN":"ところで……あんたたちはなんでまたついて来たのよ？","ENG":"But... why are you all following me?","TWN":"不過……你們為什麼跟過來了？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"에헤헤, 이번에도 잘 부탁드려요 선배!","JPN":"えへへ、今回もよろしくお願いします、先輩！","ENG":"Eh he he. We want to be in your party again, Naielle!","TWN":"嘿嘿，這次也拜託你了，前輩！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L39_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"선배를 방해하진 않을게요. 저흰 찾을 사람이 있어서 왔거든요.","JPN":"先輩の邪魔はしません。探してる人がいるので来たんです。","ENG":"We won't get in your way. We're just looking for someone.","TWN":"我不會打擾前輩的，我們是來找人的。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"찾을 사람? 그게 누군데?","JPN":"探してる人？　誰よ？","ENG":"Looking for someone? Who?","TWN":"找人？你說要找誰？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"바로 이사장님이 공인하신 <color=#ffd34c>최고의 히어로</color>!!!\xA0\xA0\xA0","JPN":"理事長公認の<color=#ffd34c>最高のヒーロー</color>！！\xA0\xA0\xA0","ENG":"The <color=#ffd34c>best hero</color> that was acclaimed by Ms. Chairwoman!!!\xA0\xA0\xA0","TWN":"就是理事長認證的<color=#ffd34c>最強英雄</color>！！！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L44_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"히어로 특별 육성반으로서 그런 엄청난 인물을 만나보지 않을 순 없지!","JPN":"ヒーロー特別育成班として、そんなすごい人物に会わないわけにはいかないじゃん！","ENG":"As a member of the Special Hero Class, we can't let an opportunity like this go to waste!","TWN":"作為英雄特別養成班的一員，怎麼能不見見那樣的偉人呢！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"허, 감히 이 몸을 두고 최고를 자처해?","JPN":"はあ？　この私を差し置いて最高を名乗ってるの？","ENG":"Huh. Who dares to claim to be the best when I'm here?","TWN":"哼，竟敢在我面前自稱最強？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"나도 알아야겠어. 더 자세한 정보는?","JPN":"その話詳しく聞かせて。","ENG":"I need to find out who this person is. Do you have any more info?","TWN":"我也想見識一下。有更詳細的資訊嗎？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"가면을 쓰고 있다는 것 외엔, 저희도 잘 몰라요.","JPN":"仮面をつけているということ以外、あたしたちもよくわかりません。","ENG":"We only know that this person wears a mask.","TWN":"只知道戴著面具，除此之外，我們也不太清楚。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"하지만 이사장님을 구해주신 분이라고 했으니까, 엄청 강한 사람일 거예요.","JPN":"でも理事長を助けてくれたって聞いたし、きっとすごく強い人のはずです。","ENG":"I heard the hero saved Ms. Chairwoman, so he must be super strong.","TWN":"肯定是個特別厲害的人，聽說還救過理事長呢。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그 정보만으론 평생을 찾아도 못 찾겠다!","JPN":"それだけの情報じゃ一生かけても見つからないわよ！","ENG":"We'll never find this person with that little information!","TWN":"光憑這些資訊，找一輩子也找不到！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그래도…… 만약 보게 되면 얼마나 강한지 시험해 볼 필요가 있겠네.","JPN":"でも……もし出会ったら、どれほど強いか試す価値はありそうね。","ENG":"But still... It would be worth finding out how strong this person actually is if I meet him.","TWN":"不過……如果見到的話，有必要試試他有多強。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"설마 히어로와 싸우겠다는 거야? 완전 빌런이잖아!","JPN":"まさかヒーローと戦うつもりなの？　それじゃヴィランじゃん！","ENG":"Are you going to fight the hero? What a villain!","TWN":"難道你想和英雄戰鬥嗎？你完全就是個反派啊！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"에엥?! 아니죠? 선배는 그럴 사람 아니잖아요!","JPN":"ええ！？　違いますよね？　先輩はそんな人じゃないでしょう！？","ENG":"Huh?! That's not true, right? You wouldn't fight a hero!","TWN":"哎？！不是吧？前輩不是那種人啊！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"너무해요 선배…….","JPN":"ひといです、先輩……","ENG":"How could you, Naielle...?","TWN":"太過分了，前輩……"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"시끄러! 애초에 나한테 질 거였으면 최고도 아닌 거잖아!","JPN":"うるさい！　そもそも私に負けるようじゃ最高でも何でもないでしょ！","ENG":"Shut it! He wouldn't be the best if he were to lose to me!","TWN":"閉嘴！如果一開始就輸給我，那根本就不是最強的！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥, 히어론지 뭔지, 그렇게나 찾고 싶다면 날 따라오도록 해.","JPN":"ふん、ヒーローか何か知らないけど、そんなに会いたいなら私について来なさい。","ENG":"Hmph! Follow me if you want to find this hero or whatever.","TWN":"哼，什麼英雄不是英雄的，如果想找到他，那就跟著我吧。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"강자끼리는 이끌리는 법이니까, 나랑 있으면 만날 확률도 높아질 거 아냐?","JPN":"強者同士はひかれ合うものよ。私といれば出会う確率も高くなるんじゃない？","ENG":"Game recognizes game, so being with me will increase your chances of meeting him, don't you think?","TWN":"強者之間總是會互相吸引的，所以和我在一起的話，遇到的機率也會更高吧？"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"선배…….","JPN":"先輩……","ENG":"Naielle...","TWN":"前輩……"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"하하, 까칠한 건지, 따뜻한 건지 컨셉 잡을 거면 하나만 해줘.","JPN":"はは、ツンツンするのか優しくするのかどっちかにしてよ。","ENG":"Haha. I really wish you'd choose a lane. Either be grumpy or be kind.","TWN":"哈哈，真不知道前輩走的是什麼風格。"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"에헤헤, 맞아요. 저는 이왕이면 따뜻한 컨셉을 해주셨으면 좋겠어요!","JPN":"えへへ、そうだね。どうせなら私は優しいほうがいいな。","ENG":"Eh he he, I agree. Personally, I wish you'd choose to be kind!","TWN":"嘿嘿，是啊。我想要前輩對我們溫和一點！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그냥 두고 갈까보다 정말……!","JPN":"まったく、本当に置いていくからね……！","ENG":"Should I just ditch them...?","TWN":"真想就這麼丟下你們走了……！"},"stage":{"bg":"LEGACY_GROUND","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"여러분…… 저흰 지금 현장에 나와 있습니다…….","JPN":"皆さん……私たちは今現場に来ています……","ENG":"So, um... We're at the scene right now...","TWN":"各位……我們現在正在現場……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"ASMR이 아니에요. 몬스터에게 들키지 않으려고 조용히 말하는 거랍니다…….","JPN":"ASMR配信ではありません。モンスターに見つからないように声を抑えているんです……","ENG":"This isn't ASMR. I'm just talking real quietly to not get noticed by monsters...","TWN":"這不是ASMR。我只是為了不被怪物發現才小聲說話的……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"에헤헤, 저도 모르게 몰입해 버렸네요……. 마치 진짜 이면세계에 온 것 같아서…….","JPN":"えへへ、つい夢中になっちゃいますね……本物の裏世界に来たみたいで……","ENG":"Eh he he, I guess I got immersed in this world... I feel like I'm really in the Counterside...","TWN":"嘿嘿，不知不覺就沉浸進去了……感覺就像真的來到了異界……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"무, 무슨 일이 일어난 거죠……?!","JPN":"な、何が起こったんでしょうか……！？","ENG":"W-what's going on...?!","TWN":"發，發生了什麼事……？！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GARAM_LEGACY_QM","text":{"KOREA":"훗훗훗. 위험에 처한 이를 돕는 건, 강자로서 당연한 도리지.\xA0","JPN":"ふふふっ。危険に晒された者を助けるのは強者の務め。\xA0","ENG":"Hah hah hah. It's the duty of the strong to aid those in danger.\xA0","TWN":"哼哼哼。幫助處於危險中的人，是強者應盡的本分。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"의리에 살고 의리에 죽는다! 우린 <color=#ffd34c>프리덤 라이더 혈맹단</color>!!","JPN":"義理と共に生き、義理に殉じる！　我々は<color=#ffd34c>フリーダム・ライダーズ血盟団</color>！！","ENG":"Live and die by loyalty! We are the <color=#ffd34c>Freedom Riders Blood Alliance</color>!!!","TWN":"為義氣而生，也為義氣而死！我們是<color=#ffd34c>自由騎士血盟團</color>！！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L36_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"맞아요. 현실이라면 모를까, 이곳에서 우린 최강의 파티라고요!","JPN":"そうです。現実はともかく、ヒミコたちはここでは最強のパーティーです！","ENG":"Yeah. We may not be the strongest in the real world, but we're the strongest party in this game!","TWN":"沒錯。如果是在現實不一定，但在這裡我們可是最強的隊伍！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"힘든 일은 혈맹원들한테 맡기고, 저희들은 편하게 구경……","JPN":"大変なことは血盟員たちに任せて、ヒミコたちは気楽に観戦……","ENG":"We can let the grunts do all the hard work while we relax and just watch over them...","TWN":"辛苦的事情就交給血盟成員，我們就舒舒服服地看熱鬧……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"드디어 저희들의 이상이 이루어진 것 같아요!","JPN":"ついに理想が叶いました！","ENG":"I think our dreams finally came true!","TWN":"我們的理想終於要實現了！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"하하, 이때 아니면 언제 갑질이란 걸 해보겠어요?","JPN":"はは、人をあごで使うなんて、こんな時だからできることですよね！","ENG":"Haha, when else would we be able to boss people around like this?","TWN":"哈哈，不趁現在耍耍威風，還等什麼時候呢？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아, 물론 아가씨의 돈이지만요…….","JPN":"あ、もちろんお嬢様のお金ですけど……","ENG":"Even if it's with Lady Xien's money...","TWN":"啊，雖然都是小姐的錢就是了……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"와~ 엄청 강해 보이는 파티가 나타났어요!","JPN":"わあ～すごく強そうなパーティーの登場です！","ENG":"Wow! A strong-looking party just appeared!","TWN":"哇～出現了一支看起來非常強大的隊伍！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"그런데, 혈맹단? 뭔가 무서운 분위기를 풍기고 있어요……!","JPN":"でも、血盟団？　なんか怖いオーラが漂ってます……！","ENG":"But, \\"Blood Alliance\\"? They're giving off scary vibes...!","TWN":"但是，血盟團？ 名字聽起來有點嚇人啊……！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"저, 저기…… 프리라이더 분들 맞으시죠? 잠시 인터뷰 가능할까요?","JPN":"あ、あの……フリーライダーの皆さん？　少しインタビューをさせてもらってもいいでしょうか？","ENG":"U-um... You're Free Riders, right? Would you be willing to participate in an interview?","TWN":"請，請問……你們是免費騎士吧？可以接受一下採訪嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"프리덤 라이더에요. 대체 우리들은 언제까지 이런 취급을 받아야 하나요…….\xA0","JPN":"フリーダム・ライダーズです。いったいいつまでこんな扱いを……\xA0","ENG":"We are called Freedom Riders. When will people start saying our name right...?\xA0","TWN":"我們是自由騎士。我們到底要被這樣對待到什麼時候……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"훗훗, 다음에는 언행에 유의해 줬으면 좋겠군.","JPN":"フッフッ、次からは言行に注意してほしいね。","ENG":"Hah hah, you'd better be careful with your words next time.","TWN":"哼哼，希望你下次注意一下。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"좋아. 우리 프리덤, 라이더에게 뭐가 궁금하지?","JPN":"いいよ。私たちフリーダム・ライダーズに何が聞きたいのかな？","ENG":"All right. So what are you curious to know about us, \\"Freedom\\" Riders?","TWN":"好吧。你對我們的自由騎士有什麼好奇的嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"혹시 여기 계신 분들이 모두 한 파티인 건가요?","JPN":"ここにいる方全員は同じパーティーなんですか？","ENG":"Is everyone here in the same party?","TWN":"請問在座的各位都是一個團隊的嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"맞아! 소수 정예로는 혈맹단이라 할 수 없지 않겠어?","JPN":"そうだ！　少数精鋭では血盟団とは名乗れないよな？","ENG":"Correct! It wouldn't be Blood Alliance with only a few elite members, would it?","TWN":"沒錯！少數精銳可稱不上是血盟團，不是嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"혈맹이라 해서 무섭게 생각하진 마. 우린 의리로 똘똘 뭉친 한 가족이거든!","JPN":"血盟と聞いて怖いと思わないでほしい。私たちは義理で結ばれた家族なんだ。","ENG":"There's no need to be scared of the term \\"Blood Alliance\\". We're just a big family united by loyalty!","TWN":"別被血盟這個名字嚇到了，我們可是一個充滿義氣的大家庭！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BLOOD_LEGACY_NULL_EXTRAA","text":{"KOREA":"하하하, 난 옛날부터 미야 씨의 팬이었거든!","JPN":"ははは、俺は昔からミヤさんのファンだったんだ！","ENG":"Ha ha ha! I'm a huge fan of yours, Miya!","TWN":"哈哈哈，我一直是米婭小姐的粉絲！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BLOOD_LEGACY_NULL_EXTRAA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BLOOD_LEGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BLOOD_LEGACY_NULL_EXTRAB","text":{"KOREA":"브로마이드는 아직 얻지 못했지만, 이 인원이면 금방 찾아낼 수 있을 겁니다.","JPN":"ブロマイドはまだ手に入れてないけど、この人数ならすぐ見つけられるでしょう。","ENG":"We haven't found the poster yet, but I'm sure we'll find it in no time with this many people.","TWN":"雖然還沒有找到海報，但以我們的人手，很快就能找到。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BLOOD_LEGACY_NULL_EXTRAA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BLOOD_LEGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BLOOD_LEGACY_NULL_EXTRAB","text":{"KOREA":"그리고 혹시…… 싸인 좀 받을 수 있을까요……?","JPN":"あとよかったら……サインもらってもいいですか……？","ENG":"And, um... could I get your autograph...?","TWN":"還有……能給我簽個名嗎……？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BLOOD_LEGACY_NULL_EXTRAA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BLOOD_LEGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"저, 저기…… 아무리 그래도 단체로 구역을 통제하시면 다른 분들에게 폐가 될 거라 생각해요.","JPN":"あ、あの……いくらなんでも、エリアを集団で占拠するのは、他の方に迷惑かと……","ENG":"U-um... I think you'll be a nuisance to the others if you block this area off as a group.","TWN":"那，那個……即便如此，集體控制一片區域的話，我認為會給其他人帶來麻煩的。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"글쎄요? 딱히 하지 말라고 규정된 것도 아니잖아요.","JPN":"そうですか？　別にダメだというルールがあるわけではないですよね？","ENG":"Oh? But it's not against any rules.","TWN":"這個嘛？也沒有明確規定不可以做啊。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"이길 수 없으면 합류하는 게 정석 아니겠어?","JPN":"勝つ見込みがないのなら、仲間になるのがお決まりだろ？","ENG":"If you can't beat them, join them. Isn't that right?","TWN":"打不過就加入，不是很正常嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"뭣하면 그쪽도 우리와 합류할래?","JPN":"なんならそっちも私たちの仲間にならないか？","ENG":"Are you interested in joining our clan?","TWN":"為難的話你們也加入我們吧？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"네?! 아뇨 전…….","JPN":"ええ！？　いいえ、私は……","ENG":"Huh?! No, I'm...","TWN":"什麼？！不，我……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"듣자 하니 혈맹단이라는 거창한 단어로 포장하던데, 결국 사람들을 매수한 것뿐이잖아?","JPN":"大げさな名前付けてるけど、結局のところ人を金で買収してるだけじゃない。","ENG":"You use grandiose words like Blood Alliance, but in the end, you're just bribing others to join.","TWN":"聽說你們用血盟團這種誇張的詞來包裝，結果不過是收買人心而已？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그렇게나 자기 실력에 자신이 없어? 한심한 놈들밖에 없네!","JPN":"そんなに自分の腕に自信がないの？　情けないやつらね。","ENG":"Do you lack confidence in your skills? What a bunch of losers!","TWN":"對自己的實力就這麼沒信心嗎？真是一群可憐蟲！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"앗, 이런 타이밍에 경쟁자의 등장!","JPN":"あっ、このタイミングでライバルの登場！","ENG":"Oh! A challenger just appeared!","TWN":"啊，這個時候竟然有競爭者出現！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"매, 매수라고?! 무슨 범죄라도 저지른 것처럼 말하지 마요!","JPN":"ば、買収！？　犯罪者扱いしないでください！","ENG":"B-bribing?! Don't talk like we're committing some kind of crime!","TWN":"收，收買？！不要說得好像我犯了什麼罪一樣！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"동료가 많은 게 뭐가 나쁜데요? 딱히 룰을 어긴 것도 아니잖아요.","JPN":"仲間が多くて何が悪いんですか？　別にルール違反でもないのに。","ENG":"What's so bad about having comrades? It's not against the rules.","TWN":"同伴多有什麼不好？又沒違反什麼規則。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"무, 물론 아가씨의 재력이 있기에 가능했지만…… 아무튼 저흰 떳떳하다고요!","JPN":"も、もちろんお嬢様の財力があったからできたことだけど……とにかく、やましいことは何もしてませんから！","ENG":"O-of course, it was only possible through Lady Xien's money... but we're not ashamed of anything!","TWN":"當，當然也是因為小姐的財力才有可能……總之我們是光明正大的！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하하, 결국 당신들은 아무것도 안 하겠다는 거잖아?","JPN":"あはは、結局あんたたちは何もしないってことでしょ？","ENG":"Haha. So, you're saying that you're not going to lift a finger, no?","TWN":"哈哈，結果你們就打算在後面看熱鬧嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"머릿수로 밀어붙이는 건 약자들이나 하는 행위인 거 몰라?","JPN":"人数で押し切ろうなんて、弱いやつらのすることなのよ？","ENG":"Don't you know that only weaklings try to win with quantity?","TWN":"你不知道用人多勢眾是弱者才會做的事嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"순진하긴, 보아하니 당신들 아카데미 학생인 것 같은데……. \xA0\xA0\xA0","JPN":"見たとこ、あなたたちはアカデミーの生徒ですよね？\xA0\xA0\xA0 ","ENG":"How naive. Seems like you're all students of the Academy...\xA0\xA0\xA0","TWN":"真是天真，我看你們好像是學院的學生……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"당신들이 관리국의 지원이나 받으면서 편하게 다니는 동안, 저흰 온갖 산전수전을 다 겪어 왔거든요?!","JPN":"あなたたちが管理局の支援を受けてのんびり過ごしている間、秋たちはあらゆる修羅場を潜り抜けてきたんですから！","ENG":"While you were all studying comfortably with the Administration's support, we went through all kinds of hardships!","TWN":"你們在享受管理局的支援時，我們可是經歷了各種艱難險阻欸？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"경험치가 다르다고요. 경험치가!","JPN":"経験値が違うんですよ、経験値が！","ENG":"The level of experience we have is different!","TWN":"經驗上就有不同，經驗上！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"경험치가 달라? 그럼 누가 먼저 퀘스트를 깨는지 내기해 봐?","JPN":"経験値？　じゃあ誰が先にクエストをクリアするか、勝負しようよ。","ENG":"Experience, eh? Then, wanna make a bet on who completes the quest first?","TWN":"經驗不同？那我們來比比看誰先完成任務吧？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L43_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"어설픈 도발이네요. 왜 우리가 당신들이랑 경쟁을 해야 하죠?","JPN":"安い挑発ですね。なぜ秋たちがそっちと競わないといけないんですか？","ENG":"You think that will provoke us? Why would we want to make a bet with you?","TWN":"好拙劣的挑釁啊。我們為什麼要和你們比呢？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"아니, 받아주도록 하지!","JPN":"いや、受けて立とう！","ENG":"No, I accept your challenge!","TWN":"不，我會接受的！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"네엣?!","JPN":"ええっ！？","ENG":"Whaaat?!","TWN":"嗯？！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"불가능한 싸움을 넘어 보려는 학생들의 청춘, 불타오르는구만……!","JPN":"不可能な戦いに挑もうとする学生たちの青春、燃えるね……！","ENG":"Young students trying to overcome an impossible fight... It sparks a flame in my heart...!","TWN":"想要挑戰不可能，這就是學生們的青春，真是熱血沸騰啊……！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"훗훗…… 오랜만에 가슴 뛰는 전투를 할 수 있겠어. 난 줄곧 이걸 원했다고!","JPN":"ふふ、久しぶりに胸が高鳴る戦いができそうだ。私はずっとこれを待ち望んでいた……！","ENG":"Hah hah... Finally! I've wanted a heart-pounding battle all this time!","TWN":"哼哼……好久沒有這麼激動了。我一直都在期待這一刻！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"하지만 봐줄 거라 생각하지 마. 우리 혈맹단은 동료를 건드는 건 용납치 않으니까!","JPN":"でも、手加減は期待しないことだ。私たち血盟団は、仲間に手を出されて黙ったりしないから！","ENG":"Don't think for a second that I'll go easy on you. The Blood Alliance won't tolerate anyone who messes with our comrades!","TWN":"但是別以為我會放過你，我們血盟團絕不容許有人動我們的同伴！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"마, 맘대로들 하세요! 저희들은 맨 뒤에 있을 테니까……","JPN":"か、勝手にしてください！　ヒミコたちは後ろに下がっているので……","ENG":"D-do whatever you want! We'll be way in the back...","TWN":"隨，隨你們吧！我們會在最後面的……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"훗훗훗! 혈맹단의 간부인 너희들이 후방에 있으면 되겠어?","JPN":"ふふふっ！　血盟団の幹部たるお前たちが後方にいてもいいはずはないだろう。","ENG":"Hah hah hah! How can the officials of our alliance stay in the rear?","TWN":"哼哼哼！你們這些血盟團的幹部怎麼能待在後方呢？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"우리 셋이 선두에 서겠다. 모두 날 따라오도록!","JPN":"私たち3人が先頭に立つ！　皆ついて来るように！","ENG":"The three of us will take the lead! Everyone, follow me!","TWN":"我們三人會走在前面，大家跟著我來！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L8_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"으아아~ 아가씨!","JPN":"わああ～お嬢様……！","ENG":"Oooh...! Lady Xien!","TWN":"啊啊～小姐！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L9_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"왜 항상 우린 이런 전개로 흘러가냐고요!!","JPN":"なんでいつもこんな展開なんですか！！","ENG":"Why do we always end up in situations like this?!","TWN":"為什麼我們總是走向這樣的結局啊！！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L10_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥, 3류 악당들 주제에 어디서 기고만장하고 있어?","JPN":"ふん！　三流悪役のくせして調子に乗るんじゃないわよ！","ENG":"Hmph! Look at those third-rate villains acting all tough!","TWN":"哼，三流惡棍還敢在這裡囂張？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"니들은 여기서 퇴장하라고!","JPN":"あんたたちにはここで退場してもらうわ！","ENG":"I'm going to log all of you out!","TWN":"趕緊給我從這裡滾出去！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"}]`);export{e as default};